# ── Dry-run execution ─────────────────────────────────────────────────────────

def test_collect_script_dry_run_exits_zero():
    script = ROOT / "scripts" / "gnm" / "collect_yahboom_episode.sh"
    result = subprocess.run(
        ["bash", str(script), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"collect_yahboom_episode.sh --dry-run failed:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    out = result.stdout
    assert "[DRY-RUN]" in out or "dry-run" in out.lower()
    assert "[OK]" in out


def test_collect_script_dry_run_prints_gate_command():
    script = ROOT / "scripts" / "gnm" / "collect_yahboom_episode.sh"
    result = subprocess.run(
        ["bash", str(script), "--dry-run", "--episode-name", "test_ep"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert "verify_yahboom_live_topics.py" in result.stdout
    assert "--strict" in result.stdout


def test_collect_script_dry_run_prints_record_command():
    script = ROOT / "scripts" / "gnm" / "collect_yahboom_episode.sh"
    result = subprocess.run(
        ["bash", str(script), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert "ros2 bag record" in result.stdout
    for topic in CANONICAL_TOPICS:
        assert topic in result.stdout


def test_collect_script_dry_run_writes_metadata():
    with tempfile.TemporaryDirectory() as tmpdir:
        script = ROOT / "scripts" / "gnm" / "collect_yahboom_episode.sh"
        ep_name = "ci_dry_run_test"
        result = subprocess.run(
            ["bash", str(script), "--dry-run", "--episode-name", ep_name],
            capture_output=True,
            text=True,
            cwd=str(ROOT),
        )
        assert result.returncode == 0
        metadata_path = (
            ROOT / "datasets" / "gnm_fleetsafe_rosbags" / ep_name / "episode_metadata.json"
        )
        assert metadata_path.exists(), "dry-run must write episode_metadata.json"
        data = json.loads(metadata_path.read_text())
        assert data["robot"] == "Yahboom ROSMASTER M3 Pro"
        assert data["dry_run"] is True
        assert data["bag_recorded"] is False
        assert "canonical_topics" in data


