def test_validator_fails_on_invalid_bag():
    """Supply a metadata.yaml with a missing topic — validator must exit non-zero."""
    with tempfile.TemporaryDirectory() as tmpdir:
        script = ROOT / "scripts" / "gnm" / "validate_yahboom_episode.py"
        ep_dir = Path(tmpdir) / "bad_episode"
        bag_dir = ep_dir / "rosbag"
        bag_dir.mkdir(parents=True)

        metadata = {
            "rosbag2_bagfile_information": {
                "duration": {"nanoseconds": 60_000_000_000},
                "message_count": 100,
                "topics_with_message_count": [
                    {
                        "topic_metadata": {"name": "/odom", "type": "nav_msgs/Odometry"},
                        "message_count": 50,
                    }
                ],
            }
        }

        try:
            import yaml
            (bag_dir / "metadata.yaml").write_text(yaml.dump(metadata))
        except ImportError:
            pytest.skip("PyYAML not installed; skipping live metadata parse test")

        result = subprocess.run(
            [sys.executable, str(script), "--episode-path", str(ep_dir)],
            capture_output=True,
            text=True,
        )
        assert result.returncode != 0, (
            "validate_yahboom_episode.py must exit non-zero when canonical topics are missing"
        )
        assert "[FAIL]" in result.stdout


def test_validator_passes_on_valid_bag():
    """Supply a complete metadata.yaml — validator must exit 0 and write report."""
    with tempfile.TemporaryDirectory() as tmpdir:
        script = ROOT / "scripts" / "gnm" / "validate_yahboom_episode.py"
        ep_dir = Path(tmpdir) / "good_episode"
        bag_dir = ep_dir / "rosbag"
        bag_dir.mkdir(parents=True)

        topics_entries = [
            {"topic_metadata": {"name": "/camera/image_raw", "type": "sensor_msgs/Image"}, "message_count": 1800},
            {"topic_metadata": {"name": "/odom", "type": "nav_msgs/Odometry"}, "message_count": 3000},
            {"topic_metadata": {"name": "/tf", "type": "tf2_msgs/TFMessage"}, "message_count": 6000},
            {"topic_metadata": {"name": "/scan", "type": "sensor_msgs/LaserScan"}, "message_count": 600},
            {"topic_metadata": {"name": "/cmd_vel", "type": "geometry_msgs/Twist"}, "message_count": 600},
        ]

        metadata = {
            "rosbag2_bagfile_information": {
                "duration": {"nanoseconds": 60_000_000_000},
                "message_count": sum(e["message_count"] for e in topics_entries),
                "topics_with_message_count": topics_entries,
            }
        }

        try:
            import yaml
            (bag_dir / "metadata.yaml").write_text(yaml.dump(metadata))
        except ImportError:
            pytest.skip("PyYAML not installed; skipping live metadata parse test")

        result = subprocess.run(
            [sys.executable, str(script), "--episode-path", str(ep_dir)],
            capture_output=True,
            text=True,
        )
        assert result.returncode == 0, (
            f"validate_yahboom_episode.py must exit 0 on a valid bag:\n"
            f"stdout: {result.stdout}\nstderr: {result.stderr}"
        )
        assert "[OK]" in result.stdout
        assert "valid" in result.stdout.lower()

        # Report JSON must be written.
        report_path = ROOT / "results" / "gnm_fleetsafe_v2_4" / "good_episode_validation.json"
        assert report_path.exists(), "Validator must write validation report JSON"
        data = json.loads(report_path.read_text())
        assert data["valid"] is True
        assert data["milestone"] == "v2.4"


